 */
export const authenticateUser = async (email: string, pass: string, sheetIdOrUrl: string): Promise<User | null> => {
  if (!sheetIdOrUrl) {
    throw new Error("Please provide a Google Sheet ID or URL");
  }

  // Construct the CSV export URL
  let fetchUrl = sheetIdOrUrl;

  // Extract GID if present to ensure we get the right sheet tab
  let gid = '';
  const gidMatch = sheetIdOrUrl.match(/[?&]gid=(\d+)/);
  if (gidMatch) {
      gid = gidMatch[1];
  }

  // If it's just an ID (no http), assume it's the ID
  if (!sheetIdOrUrl.includes('http')) {
      fetchUrl = `https://docs.google.com/spreadsheets/d/${sheetIdOrUrl}/export?format=csv`;
  } 
  // If it's a full edit URL, convert it
  else if (sheetIdOrUrl.includes('/edit')) {
      fetchUrl = sheetIdOrUrl.replace(/\/edit.*$/, '/export?format=csv');
  }
  // If it is a direct link, ensure we are asking for CSV
  else {
      const hasOutputCsv = fetchUrl.includes('output=csv');
      const hasFormatCsv = fetchUrl.includes('format=csv');

      if (!hasOutputCsv && !hasFormatCsv) {
          fetchUrl += (fetchUrl.includes('?') ? '&' : '?') + 'format=csv';
      }
  }

  // Append GID if found and not already in url
  if (gid && !fetchUrl.includes('gid=')) {
      fetchUrl += `&gid=${gid}`;
  }

  try {
    const response = await fetch(fetchUrl);

    if (!response.ok) {
        throw new Error(`Unable to access the Google Sheet (Status: ${response.status}).\n\nPlease ensure:\n1. Open your Google Sheet\n2. Go to File > Share > Publish to web\n3. Select 'Entire Document' and 'Comma-separated values (.csv)'\n4. Click 'Publish'`);
    }

    const text = await response.text();

    // Check if response is actually HTML (login page) instead of CSV
    if (text.trim().toLowerCase().startsWith('<!doctype html') || text.includes('<html')) {
        throw new Error("Access Denied: The sheet returned HTML instead of CSV.\n\nMake sure the sheet is 'Published to the web' (File > Share > Publish to web), not just 'Shared'.");
    }

    // Parse CSV (Handle newlines properly)
    const rows = text.split(/\r?\n/).map(row => row.split(',').map(c => c.trim()));

    if (rows.length < 2) throw new Error("Sheet is empty or missing headers.");

    // Normalize headers to find columns
    const headers = rows[0].map(h => h.toLowerCase().replace(/^"|"$/g, ''));
    const emailIdx = headers.findIndex(h => h.includes('email'));
    const passIdx = headers.findIndex(h => h.includes('password'));
    const nameIdx = headers.findIndex(h => h.includes('name'));
    const roleIdx = headers.findIndex(h => h.includes('role'));
    const profileIdx = headers.findIndex(h => h.includes('profile'));

    if (emailIdx === -1 || passIdx === -1) {
        throw new Error("Sheet is missing 'email' or 'password' columns.\nFound headers: " + headers.join(', '));
    }

    // Find user
    const userRow = rows.slice(1).find(row => {
        // Handle potential empty rows or parsing errors
        if (!row[emailIdx]) return false;

        const rowEmail = row[emailIdx].replace(/^"|"$/g, '').toLowerCase();
        const rowPass = row[passIdx]?.replace(/^"|"$/g, '');
        return rowEmail === email.toLowerCase() && rowPass === pass;
    });

    if (userRow) {
        const name = nameIdx !== -1 ? (userRow[nameIdx]?.replace(/^"|"$/g, '') || userRow[emailIdx].split('@')[0]) : userRow[emailIdx].split('@')[0];

        // Determine Avatar: Use profile column if exists, otherwise generate default
        let avatar = `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=0D8ABC&color=fff`;

        if (profileIdx !== -1 && userRow[profileIdx]) {
            const profileVal = userRow[profileIdx].replace(/^"|"$/g, '');
            // Simple check to ensure it looks like a URL or data string
            if (profileVal.length > 5) {
                avatar = profileVal;
            }
        }

        return {
            email: userRow[emailIdx].replace(/^"|"$/g, ''),
            name: name,
            role: (roleIdx !== -1 && userRow[roleIdx]) ? userRow[roleIdx].replace(/^"|"$/g, '') : 'User',
            avatar: avatar
        };
    }

    return null;
  } catch (error: any) {
    console.error("Auth Error:", error);
    // Pass through detailed errors
    throw error;
  }
};

