    var p = e.parameter;

    // Append row matching the formData order from the React app
    sheet.appendRow([
      p.id,
      new Date(),
      p.name,
      p.dialingCode,
      p.mobile,
      p.email,
      p.metalGroup,
      p.productCategory,
      p.budget,
      p.weight,
      p.description,
      p.source,
      p.leadGeneration,
      p.status
    ]);

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (e) {
    return ContentService.createTextOutput("Error").setMimeType(ContentService.MimeType.TEXT);
  } finally {
    lock.releaseLock();
  }
}
